const body = $input.first().json.body || $input.first().json;

const user_id = body.user_id || null;
const tool_id = (body.tool_id || '').toLowerCase().trim();

if (!user_id) throw new Error('Missing required field: user_id');
if (!tool_id) throw new Error('Missing required field: tool_id');

const validTools = [
  'launchpad_tool_1', 'launchpad_tool_2', 'launchpad_tool_3',
  'launchpad_tool_4', 'launchpad_tool_5', 'launchpad_tool_6',
  'launchpad_tool_7', 'launchpad_tool_8', 'launchpad_tool_9',
  'launchpad_tool_10'
];

if (!validTools.includes(tool_id)) {
  throw new Error(`Invalid tool_id '${tool_id}'. Must be one of: ${validTools.join(', ')}`);
}

// ── Static tool guidance map ──────────────────────────────────────────────
// Single source of truth for all tool tips, names, and first-run guidance
const toolGuidance = {
  launchpad_tool_1: {
    name:        'AI Lead Finder',
    emoji:       '🎯',
    tip:         'Start by entering your ideal customer title and top 2 pain points. The more specific you are, the higher the lead quality. Aim for 25–50 leads on your first run.',
    quick_wins:  ['Filter by job title and company size first', 'Add pain point keywords from your niche', 'Export to CSV and import into your CRM'],
    estimated_time: '8 minutes',
    first_action: 'Enter your target job title in the search field'
  },
  launchpad_tool_2: {
    name:        'Copy Generator',
    emoji:       '✍️',
    tip:         'Select your tone before generating — it sets the entire output. Start with your homepage hero headline, then your email subject lines. One piece of copy at a time gives better results than batch prompting.',
    quick_wins:  ['Always select tone before generating', 'Start with hero headline — it anchors everything else', 'Generate 3 variations and A/B test them'],
    estimated_time: '5 minutes',
    first_action: 'Choose your tone setting, then enter your product name and core benefit'
  },
  launchpad_tool_3: {
    name:        'Offer Builder',
    emoji:       '🔥',
    tip:         'The strongest offers lead with the transformation, not the features. Enter what your customer\'s life looks like after they buy — the tool builds the structure around that outcome.',
    quick_wins:  ['Lead with the transformation result', 'Add at least 2 bonuses to increase perceived value', 'Set a specific guarantee to reduce purchase friction'],
    estimated_time: '12 minutes',
    first_action: 'Describe the #1 result your customer gets in one sentence'
  },
  launchpad_tool_4: {
    name:        'Email Sequencer',
    emoji:       '📧',
    tip:         'Your first sequence should be 5 emails: welcome, value, case study, objection handler, and close. Set send days to 0, 2, 4, 6, 9 for optimal open rates. Always write subject lines last.',
    quick_wins:  ['5-email sequences outperform 3-email by 40%', 'Day 0 email gets 3x the opens — make it count', 'Write the CTA before the body copy'],
    estimated_time: '15 minutes',
    first_action: 'Set your sequence goal: book call, sell product, or nurture'
  },
  launchpad_tool_5: {
    name:        'Funnel Mapper',
    emoji:       '🗺️',
    tip:         'Map your current funnel first, then your ideal funnel — the gap between them is your highest-leverage action. Focus on the biggest drop-off point, not the top of funnel.',
    quick_wins:  ['Always map current state before ideal state', 'The biggest drop-off = your #1 priority', 'Add conversion rate estimates to each stage'],
    estimated_time: '10 minutes',
    first_action: 'Name each stage of your current sales process from lead to close'
  },
  launchpad_tool_6: {
    name:        'Competitor Analyst',
    emoji:       '🔍',
    tip:         'Enter 3 competitors minimum for pattern recognition. Focus the analysis on their offer structure and pricing page first — that\'s where positioning decisions are made.',
    quick_wins:  ['3 competitors minimum for useful patterns', 'Pricing page analysis reveals positioning gaps', 'Look for what they\'re NOT saying — that\'s your opening'],
    estimated_time: '10 minutes',
    first_action: 'Enter your top 3 competitors by name or URL'
  },
  launchpad_tool_7: {
    name:        'Ad Creative Studio',
    emoji:       '🎨',
    tip:         'Your hook is 80% of your ad performance. Generate 5 hook variations before touching the body copy. The best hooks call out the audience explicitly or make a bold, specific claim.',
    quick_wins:  ['Generate hooks first, body copy second', 'Name your audience in the hook for 2x CTR', 'Bold specific claims beat clever wordplay every time'],
    estimated_time: '8 minutes',
    first_action: 'Select your ad platform, then describe the pain point your ad solves'
  },
  launchpad_tool_8: {
    name:        'VSL Script Writer',
    emoji:       '🎬',
    tip:         'The first 30 seconds of your VSL determines if people watch the rest. Write your hook and open loop first. The promise you make in the intro must be paid off before the price reveal.',
    quick_wins:  ['First 30 seconds = 80% of your VSL effectiveness', 'State the open loop early, resolve it before the CTA', 'Read the script aloud before finalising — awkward phrases kill delivery'],
    estimated_time: '20 minutes',
    first_action: 'Decide your VSL length (5, 10, or 20 minutes) before writing'
  },
  launchpad_tool_9: {
    name:        'AI Sales Closer',
    emoji:       '💰',
    tip:         'Enter your top 3 objections before generating scripts. The best closing technique for your niche is pre-loaded — but customise the price anchoring section with your actual numbers for maximum impact.',
    quick_wins:  ['Pre-load your top 3 objections for targeted scripts', 'Customise the price anchoring with your real numbers', 'Practice the transition from discovery to close out loud'],
    estimated_time: '10 minutes',
    first_action: 'Enter your product price and your #1 most common objection'
  },
  launchpad_tool_10: {
    name:        'Business Automator',
    emoji:       '⚡',
    tip:         'Start with your most time-consuming manual task — not the most exciting one. The tool builds the automation blueprint; your job is to rank tasks by hours-per-week and tackle the biggest one first.',
    quick_wins:  ['Rank tasks by hours/week — attack the biggest drain first', 'Document the manual steps before automating them', 'Start with one automation fully working before building the next'],
    estimated_time: '15 minutes',
    first_action: 'List your top 3 manual tasks and how many hours each takes per week'
  }
};

const toolData = toolGuidance[tool_id];

return [{
  json: {
    user_id,
    tool_id,
    tool_data: toolData,
    now: new Date().toISOString()
  }
}];

const fetchResult = $input.first().json;
const origin = $('Parse, Validate + Load Tool Guidance').first().json;

const records = Array.isArray(fetchResult) ? fetchResult : [];
const already_activated = records.length > 0;
const existing_record   = records[0] || null;

return [{
  json: {
    ...origin,
    already_activated,
    existing_activated_at: existing_record?.activated_at || null
  }
}];

const insertResult = $input.first().json;
const origin = $('Check Already Activated').first().json;

const record = Array.isArray(insertResult) ? insertResult[0] : insertResult;

if (!record?.id) {
  throw new Error(`tool_first_uses INSERT returned no record for user_id: ${origin.user_id}, tool_id: ${origin.tool_id}. Check Supabase RLS and schema.`);
}

return [{
  json: {
    ...origin,
    first_use_id: record.id
  }
}];

const items = $input.all();
const origin = $('Check Already Activated').first().json;

if (!items || items.length < 2) {
  throw new Error(`Expected 2 results (first_use insert confirm + users fetch), got ${items?.length || 0}`);
}

const firstUseResult = items[0].json;
const usersResult    = items[1].json;

const usersRecord = Array.isArray(usersResult) ? usersResult[0] : usersResult;
const already_flagged = usersRecord?.first_tool_used === true;

return [{
  json: {
    ...origin,
    first_use_id:    firstUseResult.first_use_id || null,
    already_flagged
  }
}];

// Flag already set — pass through
const origin = $input.first().json;
return [{ json: { ...origin, flag_patched: false } }];

const items = $input.all();
const origin = $('Merge Insert + Flag Check').first().json;

const d = items[0].json;
const flag_patched = d.flag_patched !== false;

return [{
  json: {
    ...origin,
    flag_patched
  }
}];

const notifResult = $input.first().json;
const origin = $('Merge Flag Result').first().json;

const notif = Array.isArray(notifResult) ? notifResult[0] : notifResult;
const notif_id      = notif?.id   || null;
const notif_created = !!notif_id;

if (!notif_created) {
  console.warn(`tool_tip notification INSERT may have failed for user ${origin.user_id}, tool ${origin.tool_id}. Response: ${JSON.stringify(notifResult)}`);
}

return [{
  json: {
    ...origin,
    notif_id,
    notif_created
  }
}];
